const JSON = require('JSON');
const makeString = require('makeString');

// GTM's sandboxed JS interpreter does not support regex literals,
// so attribute lists are trimmed with plain string methods instead.
function trim(str) {
  var s = str;
  while (s.length > 0 && s.charAt(0) === ' ') { s = s.substring(1); }
  while (s.length > 0 && s.charAt(s.length - 1) === ' ') { s = s.substring(0, s.length - 1); }
  return s;
}

function splitAttrs(str) {
  var out = [];
  if (!str) return out;
  var parts = str.split(',');
  for (var i = 0; i < parts.length; i++) {
    var a = trim(parts[i]);
    if (a) out.push(a);
  }
  return out;
}

// Permitted hostnames (lower-cased) that decoration is allowed to target
var permittedHostRows = data.permittedHosts || [];
var permittedHosts = [];
for (var i = 0; i < permittedHostRows.length; i++) {
  var h = permittedHostRows[i].host;
  if (h) permittedHosts.push(makeString(h).toLowerCase());
}

// Element types + attributes to decorate, built from the checkbox/text fields
var elementTargets = [];
if (data.decorateIframe) elementTargets.push({ selector: 'iframe', attrs: splitAttrs(data.iframeAttrs) });
if (data.decorateAnchor) elementTargets.push({ selector: 'a',      attrs: splitAttrs(data.anchorAttrs) });
if (data.decorateForm)   elementTargets.push({ selector: 'form',   attrs: splitAttrs(data.formAttrs) });
if (data.decorateArea)   elementTargets.push({ selector: 'area',   attrs: splitAttrs(data.areaAttrs) });
if (data.decorateScript) elementTargets.push({ selector: 'script', attrs: splitAttrs(data.scriptAttrs) });
if (data.decorateImg)    elementTargets.push({ selector: 'img',    attrs: splitAttrs(data.imgAttrs) });

// Optional, freely parameterized additional selectors
var additionalRows = data.additionalTargets || [];
for (var j = 0; j < additionalRows.length; j++) {
  var row = additionalRows[j];
  if (row.selector) {
    elementTargets.push({ selector: row.selector, attrs: splitAttrs(row.attrs) });
  }
}

return JSON.stringify({
  permittedHosts: permittedHosts,
  elementTargets: elementTargets
});


