  },
  {
    "type": "TEXT",
    "name": "cookieNameSuffix",
    "displayName": "Cookie name suffix (optional - must match the suffix used when the cookie was written)",
    "simpleValueType": true
  },
  {
    "type": "RADIO",
    "name": "uriDecode",
    "displayName": "URI-decode cookie values before decorating",
    "radioItems": [
      {
        "value": "Yes",
        "displayValue": "Yes"
      },
      {
        "value": "No",
        "displayValue": "No"
      }
    ],
    "simpleValueType": true,
    "defaultValue": "No"
  }
]


___SANDBOXED_JS_FOR_WEB_TEMPLATE___

const getCookieValues = require('getCookieValues');
const decodeUriComponent = require('decodeUriComponent');
const JSON = require('JSON');

var suffix = data.cookieNameSuffix || '';
var rows = data.paramNames || [];
var pairs = [];

for (var i = 0; i < rows.length; i++) {
  var name = rows[i].paramName;
  if (!name) continue;

  var cookieName = name + suffix;
  var values = getCookieValues(cookieName);

  if (values && values.length > 0 && values[0]) {
    var val = values[0];
    if (data.uriDecode === 'Yes') val = decodeUriComponent(val);
    pairs.push({ name: name, value: val });
  }
}

return JSON.stringify(pairs);


